"""Synthesis for multiple-control, multiple-target Gate."""

from __future__ import annotations

from qiskit.circuit import QuantumCircuit, Gate
from qiskit._accelerate.synthesis.multi_controlled import mcmt_v_chain


def synth_mcmt_vchain(
    gate: Gate, num_ctrl_qubits: int, num_target_qubits: int, ctrl_state: int | None = None
) -> QuantumCircuit:
    """Synthesize MCMT using a V-chain.

    This uses a chain of CCX gates, using ``num_ctrl_qubits - 1`` auxiliary qubits.

    For example, a 3-control and 2-target H gate will be synthesized as::

        q_0: в”Җв”Җв– в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв– в”Җв”Җ
               в”Ӯ                        в”Ӯ
        q_1: в”Җв”Җв– в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв– в”Җв”Җ
               в”Ӯ                        в”Ӯ
        q_2: в”Җв”Җв”јв”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв– в”Җв”Җв”Җв”Җв”јв”Җв”Җ
               в”Ӯ    в”Ӯ  в”Ңв”Җв”Җв”Җв”җ       в”Ӯ    в”Ӯ
        q_3: в”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Ө H в”ңв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җ
               в”Ӯ    в”Ӯ  в””в”Җв”¬в”Җв”ҳв”Ңв”Җв”Җв”Җв”җ  в”Ӯ    в”Ӯ
        q_4: в”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Ө H в”ңв”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җ
             в”Ңв”Җв”ҙв”Җв”җ  в”Ӯ    в”Ӯ  в””в”Җв”¬в”Җв”ҳ  в”Ӯ  в”Ңв”Җв”ҙв”Җв”җ
        q_5: в”Ө X в”ңв”Җв”Җв– в”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв”јв”Җв”Җв”Җв”Җв– в”Җв”Җв”Ө X в”ң
             в””в”Җв”Җв”Җв”ҳв”Ңв”Җв”ҙв”Җв”җ  в”Ӯ    в”Ӯ  в”Ңв”Җв”ҙв”Җв”җв””в”Җв”Җв”Җв”ҳ
        q_6: в”Җв”Җв”Җв”Җв”Җв”Ө X в”ңв”Җв”Җв– в”Җв”Җв”Җв”Җв– в”Җв”Җв”Ө X в”ңв”Җв”Җв”Җв”Җв”Җ
                  в””в”Җв”Җв”Җв”ҳ          в””в”Җв”Җв”Җв”ҳ

    Args:
        gate: Base gate to be applied to the targets.
        num_ctrl_qubits: Number of control qubits.
        num_target_qubits: Number of target qubits.
        ctrl_state: Optional control state as an integer.

    Returns:
        The synthesized circuit for the MCMT gate.

    """
    if gate.num_qubits != 1:
        raise ValueError("Only single qubit gates are supported as input.")

    circ = QuantumCircuit._from_circuit_data(
        mcmt_v_chain(gate.control(annotated=False), num_ctrl_qubits, num_target_qubits, ctrl_state)
    )
    return circ
